# --- Token Validation Utilities ---

def extract_bearer_token():
    """Extract the Bearer token from the Authorization header."""
    auth_header = request.headers.get('Authorization', '')
    if auth_header.startswith('Bearer '):
        return auth_header[7:]
    # Also check query parameter as fallback (not recommended for production)
    return request.args.get('access_token')


def validate_token(token_string, required_scopes=None):
    """
    Validate an access token by checking the database.
    Returns the AccessToken object if valid, None otherwise.
    """
    if not token_string:
        return None

    token = AccessToken.query.filter_by(token=token_string).first()

    if token is None:
        log_audit('token_validation_failed', details='Token not found')
        return None

    if not token.is_valid():
        reason = 'revoked' if token.revoked else 'expired'
        log_audit('token_validation_failed', token_id=token.id, client_id=token.client_id,
                  details=f'Token is {reason}')
        return None

    # Check if the client is still active
    if not token.client.is_active:
        log_audit('token_validation_failed', token_id=token.id, client_id=token.client_id,
                  details='Client is deactivated')
        return None

    # Check scopes
    if required_scopes:
        token_scopes = set(token.get_scopes())
        required = set(required_scopes) if isinstance(required_scopes, (list, tuple)) else {required_scopes}
        if not required.issubset(token_scopes):
            missing = required - token_scopes
            log_audit('token_validation_failed', token_id=token.id, client_id=token.client_id,
                      details=f'Missing scopes: {missing}')
            return None

    log_audit('token_validated', token_id=token.id, client_id=token.client_id)
    return token


def log_audit(action, token_id=None, client_id=None, details=None):
    """Log an audit entry for token operations."""
    try:
        entry = TokenAuditLog(
            action=action,
            token_id=token_id,
            client_id=client_id,
            ip_address=request.remote_addr if request else None,
            details=details
        )
        db.session.add(entry)
        db.session.commit()
    except Exception:
        db.session.rollback()


def generate_token():
    """Generate a cryptographically secure random token."""
    return secrets.token_urlsafe(48)


# --- Decorators ---

def require_oauth(*scopes):
    """
    Decorator to protect API endpoints with OAuth 2.0 token validation.
    
    Usage:
        @require_oauth('read')
        def my_endpoint():
            ...
        
        @require_oauth('read', 'write')
        def my_endpoint():
            ...
        
        @require_oauth()  # just requires valid token, no specific scope
        def my_endpoint():
            ...
    """
    def decorator(f):
        @functools.wraps(f)
        def decorated_function(*args, **kwargs):
            token_string = extract_bearer_token()

            if not token_string:
                return jsonify({
                    'error': 'unauthorized',
                    'error_description': 'Missing access token. Provide a Bearer token in the Authorization header.'
                }), 401

            required_scopes = list(scopes) if scopes else None
            token = validate_token(token_string, required_scopes)

            if token is None:
                # Determine the specific error
                existing_token = AccessToken.query.filter_by(token=token_string).first()
                if existing_token is None:
                    return jsonify({
                        'error': 'invalid_token',
                        'error_description': 'The access token is invalid.'
                    }), 401
                elif existing_token.revoked:
                    return jsonify({
                        'error': 'invalid_token',
                        'error_description': 'The access token has been revoked.'
                    }), 401
                elif existing_token.is_expired():
                    return jsonify({
                        'error': 'invalid_token',
                        'error_description': 'The access token has expired.'
                    }), 401
                elif not existing_token.client.is_active:
                    return jsonify({
                        'error': 'invalid_token',
                        'error_description': 'The client associated with this token has been deactivated.'
                    }), 401
                else:
                    return jsonify({
                        'error': 'insufficient_scope',
                        'error_description': f'Required scopes: {", ".join(scopes)}',
                        'scope': ' '.join(scopes)
                    }), 403

            # Store token info in Flask's g object for use in the endpoint
            g.current_token = token
            g.current_client = token.client
            g.current_user_id = token.user_id
            g.token_scopes = token.get_scopes()

            return f(*args, **kwargs)

        return decorated_function
    return decorator


