@app.route('/oauth/token', methods=['POST'])
def issue_token():
    """
    Token endpoint - issues access tokens.
    Supports grant_type: client_credentials and refresh_token.
    """
    grant_type = request.form.get('grant_type')

    if grant_type == 'client_credentials':
        return _handle_client_credentials()
    elif grant_type == 'refresh_token':
        return _handle_refresh_token()
    else:
        return jsonify({
            'error': 'unsupported_grant_type',
            'error_description': f'Grant type "{grant_type}" is not supported. '
                                 f'Supported: client_credentials, refresh_token'
        }), 400


def _handle_client_credentials():
    """Handle client_credentials grant type."""
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    # Also support HTTP Basic Auth
    if not client_id or not client_secret:
        auth = request.authorization
        if auth:
            client_id = auth.username
            client_secret = auth.password

    if not client_id or not client_secret:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client credentials are required.'
        }), 401

    client = OAuthClient.query.filter_by(client_id=client_id).first()

    if client is None or client.client_secret != client_secret:
        log_audit('token_issue_failed', details=f'Invalid client credentials for client_id: {client_id}')
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Invalid client credentials.'
        }), 401

    if not client.is_active:
        log_audit('token_issue_failed', client_id=client.id, details='Client is deactivated')
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client is deactivated.'
        }), 401

    # Check requested scopes
    requested_scopes = request.form.get('scope', '').split()
    allowed_scopes = client.get_allowed_scopes()

    if requested_scopes:
        invalid_scopes = set(requested_scopes) - set(allowed_scopes)
        if invalid_scopes:
            return jsonify({
                'error': 'invalid_scope',
                'error_description': f'Invalid scopes: {", ".join(invalid_scopes)}'
            }), 400
        granted_scopes = requested_scopes
    else:
        granted_scopes = allowed_scopes

    # Generate tokens
    access_token_value = generate_token()
    refresh_token_value = generate_token()
    access_token_expires = 3600  # 1 hour
    refresh_token_expires = 86400 * 30  # 30 days

    access_token = AccessToken(
        token=access_token_value,
        client_id=client.id,
        scopes=' '.join(granted_scopes),
        expires_at=datetime.now(timezone.utc) + timedelta(seconds=access_token_expires)
    )
    db.session.add(access_token)
    db.session.flush()

    refresh_token = RefreshToken(
        token=refresh_token_value,
        access_token_id=access_token.id,
        client_id=client.id,
        expires_at=datetime.now(timezone.utc) + timedelta(seconds=refresh_token_expires)
    )
    db.session.add(refresh_token)
    db.session.commit()

    log_audit('token_issued', token_id=access_token.id, client_id=client.id,
              details=f'Scopes: {" ".join(granted_scopes)}')

    return jsonify({
        'access_token': access_token_value,
        'token_type': 'Bearer',
        'expires_in': access_token_expires,
        'refresh_token': refresh_token_value,
        'scope': ' '.join(granted_scopes)
    }), 200


def _handle_refresh_token():
    """Handle refresh_token grant type."""
    refresh_token_value = request.form.get('refresh_token')

    if not refresh_token_value:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'refresh_token is required.'
        }), 400

    refresh_token = RefreshToken.query.filter_by(token=refresh_token_value).first()

    if refresh_token is None or not refresh_token.is_valid():
        return jsonify({
            'error': 'invalid_grant',
            'error_description': 'Invalid or expired refresh token.'
        }), 400

    client = refresh_token.client
    if not client.is_active:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client is deactivated.'
        }), 401

    # Revoke old access token
    old_access_token = refresh_token.access_token
    old_access_token.revoked = True

    # Revoke old refresh token
    refresh_token.revoked = True

    # Get scopes from old token
    scopes = old_access_token.scopes

    # Generate new tokens
    access_token_value = generate_token()
    new_refresh_token_value = generate_token()
    access_token_expires = 3600
    refresh_token_expires = 86400 * 30

    new_access_token = AccessToken(
        token=access_token_value,
        client_id=client.id,
        user_id=old_access_token.user_id,
        scopes=scopes,
        expires_at=datetime.now(timezone.utc) + timedelta(seconds=access_token_expires)
    )
    db.session.add(new_access_token)
    db.session.flush()

    new_refresh_token = RefreshToken(
        token=new_refresh_token_value,
        access_token_id=new_access_token.id,
        client_id=client.id,
        expires_at=datetime.now(timezone.utc) + timedelta(seconds=refresh_token_expires)
    )
    db.session.add(new_refresh_token)
    db.session.commit()

    log_audit('token_refreshed', token_id=new_access_token.id, client_id=client.id)

    return jsonify({
        'access_token': access_token_value,
        'token_type': 'Bearer',
        'expires_in': access_token_expires,
        'refresh_token': new_refresh_token_value,
        'scope': scopes
    }), 200


@app.route('/oauth/revoke', methods=['POST'])
def revoke_token():
    """Token revocation endpoint (RFC 7009)."""
    token_value = request.form.get('token')
    token_type_hint = request.form.get('token_type_hint', 'access_token')

    if not token_value:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'token parameter is required.'
        }), 400

    revoked = False

    if token_type_hint == 'access_token':
        token = AccessToken.query.filter_by(token=token_value).first()
        if token:
            token.revoked = True
            # Also revoke associated refresh token
            if token.refresh_token:
                token.refresh_token.revoked = True
            revoked = True
            log_audit('token_revoked', token_id=token.id, client_id=token.client_id)
    elif token_type_hint == 'refresh_token':
        token = RefreshToken.query.filter_by(token=token_value).first()
        if token:
            token.revoked = True
            # Also revoke associated access token
            token.access_token.revoked = True
            revoked = True
            log_audit('refresh_token_revoked', token_id=token.id, client_id=token.client_id)

    if not revoked:
        # Try both types if hint didn't match
        access_token = AccessToken.query.filter_by(token=token_value).first()
        if access_token:
            access_token.revoked = True
            if access_token.refresh_token:
                access_token.refresh_token.revoked = True
            log_audit('token_revoked', token_id=access_token.id, client_id=access_token.client_id)
        else:
            refresh_token = RefreshToken.query.filter_by(token=token_value).first()
            if refresh_token:
                refresh_token.revoked = True
                refresh_token.access_token.revoked = True
                log_audit('refresh_token_revoked', token_id=refresh_token.id, client_id=refresh_token.client_id)

    db.session.commit()

    # RFC 7009: always return 200, even if token was not found
    return jsonify({}), 200


@app.route('/oauth/introspect', methods=['POST'])
def introspect_token():
    """Token introspection endpoint (RFC 7662) for microservices to validate tokens."""
    token_value = request.form.get('token')

    if not token_value:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'token parameter is required.'
        }), 400

    token = AccessToken.query.filter_by(token=token_value).first()

    if token is None or not token.is_valid():
        return jsonify({'active': False}), 200

    expires_at = token.expires_at if token.expires_at.tzinfo else token.expires_at.replace(tzinfo=timezone.utc)

    response = {
        'active': True,
        'scope': token.scopes,
        'client_id': token.client.client_id,
        'token_type': 'Bearer',
        'exp': int(expires_at.timestamp()),
        'iat': int(token.created_at.replace(tzinfo=timezone.utc).timestamp()) if token.created_at else None,
    }

    if token.user_id:
        response['sub'] = token.user_id

    log_audit('token_introspected', token_id=token.id, client_id=token.client_id)

    return jsonify(response), 200


